                private int gt;
                private int b;
                private int a;

                public void test() {
                if (gt == 1) {
                b = b - 150;
                a = a - 20;
                } else if (gt == 2) {
                final double br = Math.random();
                b = (int) (b - br * 40 - 80);
                } else if (gt == 3) {
                b = b - 150;
                } else {
                final double br = Math.random();
                b = (int) (b - br * 30 - 80);
                }
                }

                }


